### 4. Finally, what I wanted!

#### serializers.py

    from rest_framework_json_api import serializers
    from rest_framework_json_api.relations import ResourceRelatedField
    from rest_framework_json_api.utils import Hyperlink
    
    from django.contrib.auth import get_user_model
    
    from django.core.exceptions import ImproperlyConfigured
    from django.urls import NoReverseMatch
    
    from demo.users.models import UserProfile
    
    
    User = get_user_model()


    class ResourceRelatedFieldCustomized(ResourceRelatedField):
        """
        Customized class that offers a get_url method that does not require the
        kwargs param when reversing a view name to its corresponding full URL
        """
    
        def get_url(self, name, view_name, kwargs, request):
            # Builds a URL without requiring kwargs
    
            if not view_name:
                # Return None if the view name is not supplied
                return None
    
            try:
                url = self.reverse(view_name, request=request)
            except NoReverseMatch:
                msg = (
                    'Could not resolve URL for hyperlinked relationship using '
                    'view name "%s".'
                )
                raise ImproperlyConfigured(msg % view_name)
    
            if url is None:
                return None
    
            return Hyperlink(url, name)
    
    
    class UserSerializer(serializers.ModelSerializer):
        profile  = ResourceRelatedFieldCustomized(
            queryset=UserProfile.objects,
            related_link_view_name='profile',
        )
    
        class Meta:
            model = User
            fields = tuple(User.REQUIRED_FIELDS) + (
                User._meta.pk.name,
                User.USERNAME_FIELD,
                'joined_date',
                'profile',
            )
            read_only_fields = (
                User.USERNAME_FIELD,
                'joined_date',
            )
    
    
    class UserProfileSerializer(serializers.ModelSerializer):
        class Meta:
            model = UserProfile
            fields = ('first_name', 'last_name')

